    14→import { ActiveJsTsEditorTracker } from './ui/activeJsTsEditorTracker';
    15→import ManagedFileContextManager from './ui/managedFileContext';
    16→import { ServiceConfigurationProvider } from './configuration/configuration';
    17→import * as fileSchemes from './configuration/fileSchemes';
    18→import { standardLanguageDescriptions } from './configuration/languageDescription';
    19→import { Lazy, lazy } from './utils/lazy';
