    22→
    23→export function createLazyClientHost(
    24→	context: vscode.ExtensionContext,
    25→	onCaseInsensitiveFileSystem: boolean,
    26→	services: {
    27→		pluginManager: PluginManager;
    28→		commandManager: CommandManager;
    29→		logDirectoryProvider: ILogDirectoryProvider;
    30→		cancellerFactory: OngoingRequestCancellerFactory;
    31→		versionProvider: ITypeScriptVersionProvider;
    32→		processFactory: TsServerProcessFactory;
    33→		activeJsTsEditorTracker: ActiveJsTsEditorTracker;
    34→		serviceConfigurationProvider: ServiceConfigurationProvider;
    35→		experimentTelemetryReporter: IExperimentationTelemetryReporter | undefined;
    36→		logger: Logger;
    37→	},
    38→	onCompletionAccepted: (item: vscode.CompletionItem) => void,
    39→): Lazy<TypeScriptServiceClientHost> {
    40→	return lazy(() => {
    41→		const clientHost = new TypeScriptServiceClientHost(
    42→			standardLanguageDescriptions,
    43→			context,
    44→			onCaseInsensitiveFileSystem,
    45→			services,
    46→			onCompletionAccepted);
    47→
    48→		context.subscriptions.push(clientHost);
    49→
    50→		return clientHost;
    51→	});
    52→}
    53→
    54→export function lazilyActivateClient(
    55→	lazyClientHost: Lazy<TypeScriptServiceClientHost>,
    56→	pluginManager: PluginManager,
    57→	activeJsTsEditorTracker: ActiveJsTsEditorTracker,
    58→	onActivate: () => Promise<void> = () => Promise.resolve(),
    59→): vscode.Disposable {
    60→	const disposables: vscode.Disposable[] = [];
    61→
    62→	const supportedLanguage = [
    63→		...standardLanguageDescriptions.map(x => x.languageIds),
    64→		...pluginManager.plugins.map(x => x.languages)
    65→	].flat();
    66→
    67→	let hasActivated = false;
    68→	const maybeActivate = (textDocument: vscode.TextDocument): boolean => {
    69→		if (!hasActivated && isSupportedDocument(supportedLanguage, textDocument)) {
    70→			hasActivated = true;
    71→
    72→			onActivate().then(() => {
    73→				// Force activation
    74→				void lazyClientHost.value;
    75→
    76→				disposables.push(new ManagedFileContextManager(activeJsTsEditorTracker));
    77→			});
    78→
    79→			return true;
    80→		}
    81→		return false;
    82→	};
    83→
    84→	const didActivate = vscode.workspace.textDocuments.some(maybeActivate);
    85→	if (!didActivate) {
    86→		const openListener = vscode.workspace.onDidOpenTextDocument(doc => {
    87→			if (maybeActivate(doc)) {
    88→				openListener.dispose();
    89→			}
    90→		}, undefined, disposables);
    91→	}
    92→
    93→	return vscode.Disposable.from(...disposables);
    94→}
    95→
    96→function isSupportedDocument(
    97→	supportedLanguage: readonly string[],
    98→	document: vscode.TextDocument
    99→): boolean {
   100→	return supportedLanguage.indexOf(document.languageId) >= 0
   101→		&& !fileSchemes.disabledSchemes.has(document.uri.scheme);
   102→}
