    63→
    64→	constructor(
    65→		descriptions: LanguageDescription[],
    66→		context: vscode.ExtensionContext,
    67→		onCaseInsensitiveFileSystem: boolean,
    68→		services: {
    69→			pluginManager: PluginManager;
    70→			commandManager: CommandManager;
    71→			logDirectoryProvider: ILogDirectoryProvider;
    72→			cancellerFactory: OngoingRequestCancellerFactory;
    73→			versionProvider: ITypeScriptVersionProvider;
    74→			processFactory: TsServerProcessFactory;
    75→			activeJsTsEditorTracker: ActiveJsTsEditorTracker;
    76→			serviceConfigurationProvider: ServiceConfigurationProvider;
    77→			experimentTelemetryReporter: IExperimentationTelemetryReporter | undefined;
    78→			logger: Logger;
